                      onEventClick?.(event, dateKey);
                    }}
                    className="w-full text-left text-xs px-2 py-1 rounded-button bg-accent-magenta text-white hover:bg-accent-magenta-hover transition-all duration-standard ease-smooth truncate"
                  >
