                className="w-full px-4 py-2 rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue focus:border-transparent transition-all duration-standard ease-smooth"
              />

              {/* Category Tabs */}
              <div className="flex gap-2 flex-wrap">
                <button
                  onClick={() => setSelectedCategory('all')}
                  className={`px-3 py-1.5 rounded-button text-sm font-medium transition-all duration-standard ease-smooth ${
                    selectedCategory === 'all'
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                  }`}
                >
                  All ({availableWidgets.length})
                </button>
                {Object.entries(categoryNames).map(([category, displayName]) => {
                  const count = availableWidgets.filter(w => w.category === category).length;
                  if (count === 0) return null;

                  return (
                    <button
                      key={category}
                      onClick={() => setSelectedCategory(category as WidgetCategory)}
                      className={`px-3 py-1.5 rounded-button text-sm font-medium transition-all duration-standard ease-smooth ${
                        selectedCategory === category
                          ? 'bg-accent-blue text-white'
                          : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                      }`}
                    >
                      {displayName.split(' ')[0]} ({count})
                    </button>
                  );
                })}
              </div>

              {/* Widget Grid */}
              {availableWidgets.length === 0 ? (
                <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                  All widgets are already enabled!
                </div>
              ) : filteredAvailableWidgets.length === 0 ? (
                <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                  No widgets found matching your search.
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3">
                  {filteredAvailableWidgets.map((widget, index) => (
                    <button
                      key={widget.id}
                      onClick={() => handleEnableWidget(widget.id)}
                      className={`flex flex-col items-start gap-2 p-3 rounded-button transition-all duration-standard ease-smooth text-left group ${
                        index === selectedIndex
                          ? 'bg-accent-blue/10 ring-2 ring-accent-blue scale-105'
                          : 'bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-100 dark:hover:bg-neutral-800'
                      }`}
                    >
                      <div className="flex items-center gap-2 w-full">
                        <span className="text-2xl">{widget.icon}</span>
                        <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary flex-1 truncate">
                          {highlightText(widget.name, searchQuery)}
                        </h4>
                        <span className="text-accent-blue opacity-0 group-hover:opacity-100 transition-opacity">+</span>
                      </div>
                      <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
                        {highlightText(widget.description, searchQuery)}
                      </p>
                    </button>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="mt-6 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-accent-blue text-white rounded-button hover:bg-accent-blue-hover transition-all duration-standard ease-smooth"
          >
            Done
          </button>
        </div>
      </div>

      {/* Settings Prompt Modal (for GitHub username, etc.) */}
      {settingsPrompt && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60]">
          <div className="bg-white dark:bg-surface-dark-elevated rounded-card p-6 max-w-md w-full mx-4 border border-border-light dark:border-border-dark">
            <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
              Configure {settingsPrompt.widgetName}
            </h3>

            {settingsPrompt.widgetId === 'github' && (
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                    GitHub Username
                  </label>
                  <input
                    type="text"
                    value={githubUsername}
                    onChange={(e) => setGithubUsername(e.target.value)}
                    placeholder="octocat, username2, username3"
                    className="w-full px-3 py-2 border rounded-button bg-white dark:bg-surface-dark border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:border-transparent transition-all duration-standard ease-smooth"
                    autoFocus
                  />
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                    Enter GitHub username(s). Use commas to add multiple widgets (e.g., "username1, username2")
                  </p>
                </div>

                <div className="flex gap-3 justify-end">
                  <button
                    onClick={handleCancelSettings}
                    className="px-4 py-2 border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light dark:hover:bg-surface-dark transition-all duration-standard ease-smooth text-text-light-primary dark:text-text-dark-primary"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleSaveSettings}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
                  >
                    Save & Enable
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </Modal>
  );
};

import React from 'react';
import { useWidgetStore } from '../stores/useWidgetStore';

interface WidgetResizeHandleProps {
  widgetId: string;
  currentSize: 1 | 2 | 3;
}

/**
 * Widget Resize Handle Component
 *
 * Provides UI controls to resize widgets between 1x, 2x, and 3x column spans.
 * - Mobile (< 768px): All widgets display as 1 column (sizes ignored)
 * - Tablet/Desktop (≥ 768px): 2-column grid
 *   - 1x = 1 column (50% width)
 *   - 2x = 2 columns (100% width)
 *   - 3x = 2 columns (100% width, treated same as 2x in 2-col grid)
 *
 * Shows on hover with opacity-0 → group-hover:opacity-100
 */
export const WidgetResizeHandle: React.FC<WidgetResizeHandleProps> = ({ widgetId, currentSize }) => {
  const setWidgetSize = useWidgetStore((state) => state.setWidgetSize);

  return (
    <div className="resize-handle-group absolute bottom-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity z-10">
      <button
        onClick={() => setWidgetSize(widgetId, 1)}
        className={`px-2 py-1 text-xs rounded font-medium transition-colors ${
          currentSize === 1
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 1 column width"
        title="Small (1x)"
      >
        1x
      </button>
      <button
        onClick={() => setWidgetSize(widgetId, 2)}
        className={`px-2 py-1 text-xs rounded font-medium transition-colors ${
          currentSize === 2
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 2 columns width"
        title="Medium (2x)"
      >
        2x
      </button>
      <button
        onClick={() => setWidgetSize(widgetId, 3)}
        className={`px-2 py-1 text-xs rounded font-medium transition-colors ${
          currentSize === 3
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 3 columns width (full row)"
        title="Large (3x)"
      >
        3x
      </button>
    </div>
  );
};

