/**
 * Tasks Summary Widget
 *
 * Displays task statistics: Due Today, In Progress, Completed
 * Focused widget for task overview with navigation to full Kanban view
 */

import React from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useNavigate } from 'react-router-dom';

export const TasksSummaryWidget: React.FC = () => {
  const { tasks } = useKanbanStore();
  const navigate = useNavigate();

  // Task statistics
  const dueToday = tasks.filter((t) => {
    if (!t.dueDate) return false;
    const due = new Date(t.dueDate);
    const today = new Date();
    return due.toDateString() === today.toDateString();
  });

  const inProgress = tasks.filter((t) => t.status === 'inprogress');
  const completed = tasks.filter((t) => t.status === 'done');

  return (
    <BaseWidget title="Tasks Summary" icon="📊">
      <div className="p-4 space-y-4">
        {/* Task Counts Grid */}
        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <div className="text-3xl font-bold text-status-warning">
              {dueToday.length}
            </div>
            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
              Due Today
            </div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-accent-blue">
              {inProgress.length}
            </div>
            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
              In Progress
            </div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-status-success">
              {completed.length}
            </div>
            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
              Completed
            </div>
          </div>
        </div>

        {/* View All Button */}
        <button
          onClick={() => navigate('/tasks')}
          className="w-full px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth text-sm font-medium"
        >
          View All Tasks →
        </button>
      </div>
    </BaseWidget>
  );
};

