/**
 * Tasks Quick Add Widget
 *
 * Simple widget for quickly adding tasks to the Kanban board
 * Focused, single-purpose interface
 */

import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';

export const TasksQuickAddWidget: React.FC = () => {
  const { addTask } = useKanbanStore();
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      addTask({
        title: input.trim(),
        description: '',
        status: 'todo',
        priority: 'medium',
        tags: [],
        startDate: null,
        dueDate: null,
      });
      setInput('');
    }
  };

  return (
    <BaseWidget title="Quick Add Task" icon="➕">
      <div className="p-4">
        <form onSubmit={handleSubmit} className="space-y-3">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Add a task..."
            className="w-full px-4 py-2 border rounded-button transition-all duration-standard ease-smooth
                       bg-white dark:bg-surface-dark
                       text-text-light-primary dark:text-text-dark-primary
                       border-border-light dark:border-border-dark
                       focus:outline-none focus:ring-2 focus:ring-accent-blue"
            autoFocus
          />
          <button
            type="submit"
            disabled={!input.trim()}
            className="w-full px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 disabled:cursor-not-allowed text-white rounded-button transition-all duration-standard ease-smooth font-medium"
          >
            Add Task
          </button>
        </form>
      </div>
    </BaseWidget>
  );
};

