import { getWidget } from '../widgets/Dashboard/WidgetRegistry';

interface WidgetSettingsModalProps {
  widgetId: string;
  isOpen: boolean;
  onClose: () => void;
}

export const WidgetSettingsModal: React.FC<WidgetSettingsModalProps> = ({
  widgetId,
  isOpen,
  onClose,
}) => {
  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
  const setWidgetSize = useWidgetStore((state) => state.setWidgetSize);
  const currentSize = widgetSizes[widgetId] || 1;
  const [selectedSize, setSelectedSize] = useState<1 | 2 | 3>(currentSize);

  const widgetMeta = getWidget(widgetId);
  const isWeatherMap = widgetId === 'weathermap';

  const handleApply = () => {
    setWidgetSize(widgetId, selectedSize);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50"
        onClick={onClose}
      />

      {/* Modal */}
      <div className="fixed inset-0 flex items-center justify-center z-50 p-4">
        <div
          className="bg-white dark:bg-surface-dark-elevated rounded-button shadow-2xl border border-border-light dark:border-border-dark w-full max-w-md"
          onClick={(e) => e.stopPropagation()}
        >
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-4 border-b border-border-light dark:border-border-dark">
            <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
              Widget Settings
            </h2>
            <button
              onClick={onClose}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark rounded-button transition-all duration-standard ease-smooth"
              aria-label="Close"
            >
              <svg
                className="w-5 h-5 text-text-light-secondary dark:text-text-dark-secondary"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </button>
          </div>

          {/* Content */}
          <div className="px-6 py-5 space-y-6">
            {/* Widget Info */}
            <div>
              <h3 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                {widgetMeta?.name || widgetId}
              </h3>
              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                {widgetMeta?.description || 'Configure widget settings'}
              </p>
            </div>

            {/* Size Selector */}
            {!isWeatherMap && (
              <div>
                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-3">
                  Widget Size
                </label>
                <div className="grid grid-cols-3 gap-3">
                  {([1, 2, 3] as const).map((size) => (
                    <button
                      key={size}
                      onClick={() => setSelectedSize(size)}
                      className={`
                        relative px-4 py-3 rounded-button border-2 transition-all duration-standard ease-smooth
                        ${selectedSize === size
                          ? 'border-accent-blue bg-accent-blue/10 dark:bg-accent-blue/20'
                          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                        }
                      `}
                    >
                      <div className="text-center">
                        <div className="text-xl font-bold text-text-light-primary dark:text-text-dark-primary">
                          {size}x
                        </div>
                        <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-1">
                          {size === 1 ? 'Compact' : size === 2 ? 'Medium' : 'Wide'}
                        </div>
                      </div>
                      {selectedSize === size && (
                        <div className="absolute top-2 right-2 w-4 h-4 bg-accent-blue rounded-full flex items-center justify-center">
                          <svg
                            className="w-3 h-3 text-white"
                            fill="currentColor"
                            viewBox="0 0 20 20"
                          >
                            <path
                              fillRule="evenodd"
                              d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                              clipRule="evenodd"
                            />
                          </svg>
                        </div>
                      )}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {isWeatherMap && (
              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Weather Map size is locked to ensure optimal display of the interactive map.
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-border-light dark:border-border-dark">
            <button
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark rounded-button transition-all duration-standard ease-smooth"
            >
              Cancel
            </button>
            <button
              onClick={handleApply}
              className="px-4 py-2 text-sm font-medium bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
            >
              Apply
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

